#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;

const int N=105;
const double eps=1e-6;

int n,match[N],last[N];
double w[N][N],la[N],lb[N],upd[N];
bool va[N],vb[N];
pair<int,int> pa[N],pb[N];

int cmp(double a,double b){
    if(fabs(a-b)<=eps)
        return 0;
    return a<b?-1:1;
}

bool dfs(int x,int fa){
    va[x]=1;
    for(int y=1;y<=n;y++)
        if(!vb[y]){
            if(!cmp(la[x]+lb[y],w[x][y])){
                vb[y]=1,last[y]=fa;
                if(!match[y] || dfs(match[y],y)){
					match[y]=x;
                    return true;
                }
            }else if(upd[y]>la[x]+lb[y]-w[x][y]){
                upd[y]=la[x]+lb[y]-w[x][y];
                last[y]=fa;
            }
        }
    return false;
}

void KM(){
    for(int i=1;i<=n;i++){
        la[i]=-1e18,lb[i]=0;
        for(int j=1;j<=n;j++)
            la[i]=max(la[i],w[i][j]);
    }
    for(int i=1,st;i<=n;i++){
        memset(va,0,sizeof(va));
        memset(vb,0,sizeof(vb));
        memset(last,0,sizeof(last));
        memset(upd,0x7f,sizeof(upd));
        match[0]=i,st=0;
        while(match[st]){
            double del=1e18;
            if(dfs(match[st],st))
            	break;
            for(int j=1;j<=n;j++)
                if(!vb[j] && upd[j]<del){
                    del=upd[j];
                    st=j;
                }
            for(int j=1;j<=n;j++){
                if(va[j])
                    la[j]-=del;
                if(vb[j])
                    lb[j]+=del;
                else
                	upd[j]-=del;
            }
        	vb[st]=1;
        }
        while(st){
            match[st]=match[last[st]];
            st=last[st];
        }
    }
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&pb[i].x,&pb[i].y);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&pa[i].x,&pa[i].y);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)
            w[i][j]=-sqrt((pa[i].x-pb[j].x)*(pa[i].x-pb[j].x)+(pa[i].y-pb[j].y)*(pa[i].y-pb[j].y));
    KM();
    for(int i=1;i<=n;i++)
        printf("%d\n",match[i]);
    return 0;
}
